package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
)

// HandleProductSearch processes product search requests, renders results, and logs analytics
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract search keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Server-side analytics: log search event with contextual metadata
	log.Printf(
		"[Analytics] Search query received: keyword=%q, remote_addr=%q, user_agent=%q, path=%q",
		keyword,
		r.RemoteAddr,
		r.UserAgent(),
		r.URL.Path,
	)

	// Escape keyword to prevent XSS vulnerabilities in HTML output
	escapedKeyword := html.EscapeString(keyword)

	// Set response content type to HTML with proper charset
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Construct HTML response with required title element
	responseHTML := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
    <!-- Client-side analytics configuration can be added here -->
</head>
<body>
    <h2>Search Results: %s</h2>
    <!-- Product result listing would be rendered here -->
    <!-- Client-side analytics event tracking script can be inserted here -->
</body>
</html>`, escapedKeyword)

	// Write the HTML response to the client
	_, err := w.Write([]byte(responseHTML))
	if err != nil {
		log.Printf("Error writing search response: %v", err)
	}
}

func main() {
	// Register the search handler at the /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	log.Println("Server starting on :8080. Test with: http://localhost:8080/search?keyword=your-product")
	// Start HTTP server on port 8080
	log.Fatal(http.ListenAndServe(":8080", nil))
}

