package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch processes product search requests, displays results and logs search analytics
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract search keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics: Log search event with metadata (basic analytics implementation)
	log.Printf(
		"[Search Analytics] Keyword: %q | Remote Address: %q | Timestamp: %s",
		keyword,
		r.RemoteAddr,
		time.Now().Format(time.RFC3339),
	)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape keyword to prevent XSS attacks before inserting into HTML
	safeKeyword := html.EscapeString(keyword)

	// Render HTML response with the required heading
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <!-- Additional product result content can be added here -->
</body>
</html>`, safeKeyword)
}

func main() {
	// Register the search handler at the /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	log.Println("Server starting on :8080. Test with: http://localhost:8080/search?keyword=laptop")
	// Start HTTP server on port 8080
	log.Fatal(http.ListenAndServe(":8080", nil))
}

