)

// HandleProductSearch processes product search requests, renders results and tracks analytics
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract search keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Log search event for analytics (captures keyword, user IP and user agent)
	log.Printf("analytics: search_event keyword=%q remote_addr=%s user_agent=%q",
		keyword, r.RemoteAddr, r.UserAgent())

	// Set response content type to HTML with proper charset
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape user input to prevent XSS attacks before rendering into HTML
	escapedKeyword := html.EscapeString(keyword)

	// Render valid HTML response with required heading
	_, err := fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results: %s</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <!-- Product result listings would be rendered here -->
</body>
</html>`, escapedKeyword, escapedKeyword)

	// Handle rendering errors gracefully
	if err != nil {
		log.Printf("failed to render search page: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

func main() {
	// Register the search handler at /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	log.Println("Server running on :8080. Test with http://localhost:8080/search?keyword=your-search-term")
	// Start HTTP server on port 8080
	log.Fatal(http.ListenAndServe(":8080", nil))
}

