// HandleProductSearch processes product search requests, displays results, and tracks analytics events
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract search keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics: Track search event with metadata for analysis
	log.Printf(
		"[Analytics] Search event: timestamp=%s, keyword=%q, remote_addr=%s, user_agent=%q",
		time.Now().Format(time.RFC3339),
		keyword,
		r.RemoteAddr,
		r.UserAgent(),
	)

	// Escape keyword to prevent cross-site scripting (XSS) vulnerabilities
	escapedKeyword := html.EscapeString(keyword)

	// Set response content type to HTML as required
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Render HTML response with the required heading
	_, err := fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <!-- Product listing content would be added here in a production implementation -->
</body>
</html>`, escapedKeyword)

	// Handle response writing errors
	if err != nil {
		log.Printf("Failed to generate search response: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

func main() {
	// Register the search handler at the /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start HTTP server on port 8080
	log.Println("Server running on http://localhost:8080")
	log.Println("Test endpoint: http://localhost:8080/search?keyword=your-search-term")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

