func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract search keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Collect and log analytics data (can be extended to send to external analytics services)
	analyticsEvent := SearchAnalyticsEvent{
		Timestamp:   time.Now(),
		Keyword:     keyword,
		ClientIP:    r.RemoteAddr,
		UserAgent:   r.UserAgent(),
		RequestPath: r.URL.Path,
	}

	// Serialize event to JSON for structured logging
	eventJSON, err := json.Marshal(analyticsEvent)
	if err != nil {
		log.Printf("failed to serialize analytics event: %v", err)
	} else {
		log.Printf("search_analytics: %s", string(eventJSON))
	}

	// Escape keyword to prevent XSS attacks before rendering in HTML
	safeKeyword := html.EscapeString(keyword)

	// Set response content type to HTML
