package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch processes product search requests, renders results, and logs search events for analytics
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Restrict to GET requests since search uses URL query parameters
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Extract search keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Log analytics data: timestamp, search term, user IP, and user agent for search tracking
	log.Printf(
		"analytics: search_event timestamp=%q keyword=%q user_ip=%q user_agent=%q",
		time.Now().Format(time.RFC3339),
		keyword,
		r.RemoteAddr,
		r.UserAgent(),
	)

	// Escape keyword to prevent XSS vulnerabilities when rendered in HTML
	safeKeyword := html.EscapeString(keyword)

	// Set response content type to HTML with UTF-8 encoding
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Render HTML response with the required search results heading
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <!-- Product listing content can be added here in production -->
</body>
</html>`, safeKeyword)
}

func main() {
	// Register the search handler at the /search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	log.Println("Server running on http://localhost:8080")
	// Start HTTP server on port 8080, log any startup/runtime errors
	log.Fatal(http.ListenAndServe(":8080", nil))
}

